namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly string[] _templates =
    [
        "Your build completed successfully.",
        "New comment on your pull request.",
        "Deployment to staging finished.",
        "Disk usage exceeded 80% on server-3.",
        "User admin@example.com signed in.",
        "Scheduled backup completed.",
        "New team member joined the project.",
        "Security scan found 0 vulnerabilities.",
        "Certificate renewal reminder: 7 days left.",
        "Database migration applied successfully."
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>();
            for (var i = 0; i < 3; i++)
            {
                items.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = _templates[Random.Shared.Next(_templates.Length)],
                    Timestamp = DateTime.UtcNow.AddMinutes(-Random.Shared.Next(1, 60))
                });
            }
            return Task.FromResult(items);
        }
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>();
            if (Random.Shared.Next(3) == 0)
            {
                items.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = _templates[Random.Shared.Next(_templates.Length)],
                    Timestamp = DateTime.UtcNow
                });
            }
            return Task.FromResult(items);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Items is not null)
    {
        <span class="badge">@Items.Count</span>
    }
</h1>

@if (Items is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (Items.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="notification-list">
        @foreach (var item in Items)
        {
            <li>
                <strong>@item.Message</strong>
                <small>@item.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch when state was restored from prerender
        Items ??= await NotificationSvc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is never called during prerender, so the polling
        // loop only starts once the page is truly interactive.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newItems = await NotificationSvc.CheckForNewNotificationsAsync();
            if (newItems.Count > 0)
            {
                Items ??= [];
                Items.InsertRange(0, newItems);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

h1 {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.badge {
    background-color: #d9534f;
    color: white;
    font-size: 0.55em;
    padding: 0.25em 0.6em;
    border-radius: 999px;
    vertical-align: middle;
}

.notification-list {
    list-style: none;
    padding: 0;
}

.notification-list li {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    padding: 0.75rem 0;
    border-bottom: 1px solid #e0e0e0;
}

.notification-list li small {
    color: #888;
}

