namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly string[] _templates =
    [
        "Your build completed successfully.",
        "New comment on your pull request.",
        "Deployment to staging finished.",
        "Disk usage exceeded 80% on server-3.",
        "User admin@example.com signed in.",
        "Scheduled backup completed.",
        "New team member joined the project.",
        "Security scan found 0 vulnerabilities.",
        "Certificate renewal reminder: 7 days left.",
        "Database migration applied successfully."
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>();
            for (var i = 0; i < 3; i++)
            {
                items.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = _templates[Random.Shared.Next(_templates.Length)],
                    Timestamp = DateTime.UtcNow.AddMinutes(-Random.Shared.Next(1, 60))
                });
            }
            return Task.FromResult(items);
        }
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>();
            if (Random.Shared.Next(3) == 0)
            {
                items.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = _templates[Random.Shared.Next(_templates.Length)],
                    Timestamp = DateTime.UtcNow
                });
            }
            return Task.FromResult(items);
        }
    }
}

